type CurrencyApiLatest = {
  amount?: number
  base?: string
  date?: string
  rates?: Record<string, number>
}

type OpenExchangeLatest = {
  result?: string
  provider?: string
  documentation?: string
  time_last_update_utc?: string
  base_code?: string
  rates?: Record<string, number>
}

type FrankfurterRateResponse = {
  amount?: number
  base?: string
  quote?: string
  date?: string
  rate?: number
}

const toIsoDate = (date: Date) => date.toISOString().slice(0, 10)

function subtractDays(date: Date, days: number) {
  const next = new Date(date)
  next.setDate(next.getDate() - days)
  return next
}

function buildFlatTrend(pointsCount: number, rate: number) {
  const end = new Date()
  const safeCount = Math.max(pointsCount, 2)
  const start = subtractDays(end, safeCount - 1)
  return Array.from({ length: safeCount }, (_, index) => {
    const pointDate = new Date(start)
    pointDate.setDate(start.getDate() + index)
    return { date: toIsoDate(pointDate), rate }
  })
}


function normalizeUtcDate(date: Date) {
  return new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()))
}

function addDays(date: Date, days: number) {
  const next = new Date(date)
  next.setUTCDate(next.getUTCDate() + days)
  return next
}

function differenceInDays(start: Date, end: Date) {
  const startMs = normalizeUtcDate(start).getTime()
  const endMs = normalizeUtcDate(end).getTime()
  return Math.max(0, Math.round((endMs - startMs) / 86400000))
}

function buildSampleDates(rangeKey: string) {
  const end = normalizeUtcDate(new Date())
  const configs: Record<string, { start: Date; targetPoints: number }> = {
    '1D': { start: addDays(end, -1), targetPoints: 2 },
    '5D': { start: addDays(end, -5), targetPoints: 6 },
    '1M': { start: addDays(end, -31), targetPoints: 8 },
    '1Y': { start: addDays(end, -365), targetPoints: 12 },
    '5Y': { start: addDays(end, -(365 * 5)), targetPoints: 20 },
    Max: { start: normalizeUtcDate(new Date('1999-01-04T00:00:00Z')), targetPoints: 24 },
  }
  const selected = configs[rangeKey] ?? configs['1M']
  const totalDays = differenceInDays(selected.start, end)
  const points = Math.max(2, selected.targetPoints)
  if (totalDays <= points - 1) {
    return Array.from({ length: totalDays + 1 }, (_, index) => toIsoDate(addDays(selected.start, index)))
  }
  const step = totalDays / (points - 1)
  const dates = new Set<string>()
  for (let index = 0; index < points; index += 1) {
    const offset = Math.round(step * index)
    dates.add(toIsoDate(addDays(selected.start, offset)))
  }
  dates.add(toIsoDate(end))
  return Array.from(dates).sort((a, b) => a.localeCompare(b))
}

async function fetchFrankfurterRateOnOrBefore(base: string, quote: string, date: string) {
  const parsed = new Date(`${date}T00:00:00Z`)
  for (let attempt = 0; attempt < 6; attempt += 1) {
    const tryDate = toIsoDate(addDays(parsed, -attempt))
    try {
      const result = await fetchJson<FrankfurterRateResponse>(`https://api.frankfurter.dev/v2/rate/${base}/${quote}?date=${tryDate}`)
      const rate = Number(result?.rate ?? 0)
      if (Number.isFinite(rate) && rate > 0) {
        return { date: result?.date || tryDate, rate }
      }
    } catch {
      // Try the prior working day. Some providers do not return weekend data.
    }
  }
  return null
}

async function fetchHistoricalTrend(base: string, quote: string, rangeKey: string) {
  const sampleDates = buildSampleDates(rangeKey)
  const results = await Promise.all(sampleDates.map((date) => fetchFrankfurterRateOnOrBefore(base, quote, date)))
  const deduped = new Map<string, number>()
  results.forEach((item) => {
    if (!item) return
    deduped.set(item.date, item.rate)
  })
  return Array.from(deduped.entries())
    .map(([date, rate]) => ({ date, rate }))
    .sort((a, b) => a.date.localeCompare(b.date))
}

async function fetchLatestRateWithFallback(fromCurrency: string, toCurrency: string) {
  try {
    const latest = await fetchJson<OpenExchangeLatest>(`https://open.er-api.com/v6/latest/${fromCurrency}`)
    if (latest.result === 'success' && latest.rates) {
      const rate = Number(latest.rates[toCurrency] ?? 0)
      if (Number.isFinite(rate) && rate > 0) {
        return {
          rate,
          latestDate: latest.time_last_update_utc ?? '',
          currencyMap: Object.fromEntries(Object.keys(latest.rates).map((code) => [code, FALLBACK_CURRENCIES[code] ?? code])),
          provider: 'ExchangeRate-API',
        }
      }
    }
  } catch {
    // Fall through to Frankfurter.
  }

  const frankfurterLatest = await fetchJson<FrankfurterRateResponse>(`https://api.frankfurter.dev/v2/rate/${fromCurrency}/${toCurrency}`)
  const fallbackRate = Number(frankfurterLatest?.rate ?? 0)
  if (!Number.isFinite(fallbackRate) || fallbackRate <= 0) {
    throw new Error('Conversion rate unavailable right now.')
  }
  return {
    rate: fallbackRate,
    latestDate: frankfurterLatest?.date ?? '',
    currencyMap: null as Record<string, string> | null,
    provider: 'Frankfurter',
  }
}

async function fetchJson<T>(url: string): Promise<T> {
  const response = await fetch(url)
  if (!response.ok) throw new Error(`Request failed (${response.status})`)
  return response.json() as Promise<T>
}

