  !!TAWK_PROPERTY_ID &&
  !!TAWK_WIDGET_ID &&
  TAWK_PROPERTY_ID !== 'YOUR_TAWK_PROPERTY_ID' &&
  TAWK_WIDGET_ID !== 'YOUR_TAWK_WIDGET_ID'

function loadTawkWidget() {
  if (!TAWK_ENABLED || typeof window === 'undefined') return
  if (window.__budgetlyTawkLoaded) return

  window.Tawk_API = window.Tawk_API || {}
  window.Tawk_LoadStart = new Date()

  const script = document.createElement('script')
  script.async = true
  script.src = `https://embed.tawk.to/${TAWK_PROPERTY_ID}/${TAWK_WIDGET_ID}`
  script.charset = 'UTF-8'
  script.setAttribute('crossorigin', '*')
  script.dataset.budgetlyTawk = 'true'
  document.head.appendChild(script)
  window.__budgetlyTawkLoaded = true
}


